class Solution:
    def maximumLength(self, s: str) -> int:
        max_length = -1
        for char in set(s):
            current_length = 0
            count = 0
            for c in s:
                if c == char:
                    current_length += 1
                else:
                    if current_length > 0:
                        count += 1 if current_length >= 3 else 0
                        current_length = 0
            if current_length > 0:
                count += 1 if current_length >= 3 else 0
            if count >= 3:
                max_length = max(max_length, current_length)
        return max_length
